{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Income must be less than or equal to 200% of the Federal Poverty Guidelines (updated annually). Guidelines effective April 8, 2025: Household of 1: $31,300; 2: $42,300; 3: $53,300; 4: $64,300; 5: $75,300; 6: $86,300. Add $11,000 for each additional member. Income is gross cash receipts before taxes from the applicable tax year(s); excludes child support, tax refunds, college scholarships, etc.[1]",
    "asset_limits": "No asset limits mentioned.[1][2]",
    "other_requirements": ["Must reside in West Virginia.", "Dwelling must meet building eligibility requirements (structurally adaptable for weatherization materials).", "Renters need landlord permission.", "Priority on waitlist for households with elderly (60+), disabled, children (18 or younger), high energy burden, or high energy use.[1][2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Energy conservation measures including air sealing, insulation in walls/floors, duct sealing, heating/cooling system repairs or tune-ups, electrical improvements; aimed at reducing utility costs and improving safety/comfort. No fixed dollar amount or hours; services based on energy audit.[1][2][4][7]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local community action agency serving your county (in-person, phone, or mail application).", "Some providers offer online application (e.g., MountainHeart at unspecified link).[7]", "Examples: CASEWV (casewv.org), MountainHeart (call 304-682-8271 ext. 101 or 117 for Wyoming/Fayette Counties), Southwestern Community Action Council (scacwv.org).[3][7][8]"],
    "processing_time": "Eligibility determination after application (time-consuming due to income verification); then placed on waitlist for energy audit and services. No specific timeline given.[2]",
    "waitlist": "Yes, all eligible applicants placed on waitlist; prioritized by points for high energy burden/use, elderly (60+), disabled, children.[1][2]",
    "forms": ["Local agency application form (takes ~20 minutes; no specific name/number statewide).[2]"],
    "documents": ["Written proof of all gross income for prior year (e.g., tax returns, pay stubs).", "Household details: number of people, home construction date, utility providers/account numbers.", "For renters: landlord permission.[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide via local community action agencies by county; must contact agency serving your county.[1][2][6]",
    "regional_variations": "Administered by different local community action agencies/providers per county/region (e.g., CASEWV, MountainHeart for Wyoming/Fayette, Southwestern CAC); potential differences in wait times or processes, but core eligibility/services consistent.[2][3][7][8]",
    "offices_or_providers": ["Local community action agencies throughout WV (12 agencies funded in recent grants); examples: wvcad.org for statewide info, casewv.org, mthtwv.com, scacwv.org.[1][3][6][7][8]"]
  },
  "official_source": "https://wvcad.org/sustainability/weatherization-assistance-program",
  "gotchas": ["Must verify latest Federal Poverty Guidelines annually as they update (e.g., April 2025 figures).[1]", "Renters need landlord permission first.[2]", "Income verification is detailed and time-consuming; all sources required.[2]", "Dwelling must pass building eligibility (not all homes qualify).[1]", "Priority waitlist favors elderly/disabled/children/high energy needs, so non-priority may wait longer.[1]", "Separate RRP for heating repairs under DHHR (60% SMI, elderly/disabled priority) via some agencies.[3]"],
  "data_shape_notes": "Administered via county-specific community action agencies; waitlist with priority tiers (elderly 60+, disabled, children, high energy burden); income at 200% FPG with table by household size; building eligibility required."
}

